export default function TextImage({ section }) {
  const { title, subtitle, content, image, buttonText, buttonLink } = section || {};

  return (
    <section className="py-16 md:py-20 bg-white">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-12 items-center">
          <div className={image && image.includes('/') ? '' : 'md:order-2'}>
            {title && (
              <h2 className="text-3xl md:text-4xl font-bold text-gray-900 mb-4">
                {title}
              </h2>
            )}
            {subtitle && (
              <p className="text-xl text-gray-600 mb-6">{subtitle}</p>
            )}
            {content && (
              <div 
                className="prose text-gray-600 mb-6"
                dangerouslySetInnerHTML={{ __html: content }}
              />
            )}
            {buttonText && buttonLink && (
              <a
                href={buttonLink}
                className="inline-block bg-yellow-500 text-white px-6 py-3 rounded-lg font-medium hover:bg-yellow-600 transition-colors"
              >
                {buttonText}
              </a>
            )}
          </div>

          {image && image.includes('/') && (
            <div className="relative">
              <img
                src={image}
                alt={title || 'Image'}
                className="rounded-xl shadow-lg w-full h-auto"
              />
            </div>
          )}
        </div>
      </div>
    </section>
  );
}
